            #region Snippet:ContentUnderstandingAnalyzeUrlAsync
            // You can replace this URL with your own publicly accessible document URL.
            Uri uriSource = new Uri("https://raw.githubusercontent.com/Azure-Samples/azure-ai-content-understanding-assets/main/document/mixed_financial_docs.pdf");

            Operation<AnalysisResult> operation = await client.AnalyzeAsync(
                WaitUntil.Completed,
                "prebuilt-documentSearch",
                inputs: new[]
                {
                    new AnalysisInput
                    {
                        Uri = uriSource
                    }
                });

            AnalysisResult result = operation.Value;
            AnalysisContent content = result.Contents!.First();
            Console.WriteLine("Markdown:");
            Console.WriteLine(content.Markdown);

            // Cast AnalysisContent to DocumentContent to access document-specific properties
            // DocumentContent derives from AnalysisContent and provides additional properties
            // to access full information about document, including Pages, Tables and many others
            DocumentContent documentContent = (DocumentContent)content;
            Console.WriteLine($"Pages: {documentContent.StartPageNumber} - {documentContent.EndPageNumber}");

            // Check for pages
            if (documentContent.Pages != null && documentContent.Pages.Count > 0)
            {
                Console.WriteLine($"Number of pages: {documentContent.Pages.Count}");
                foreach (var page in documentContent.Pages)
                {
                    var unit = documentContent.Unit?.ToString() ?? "units";
                    Console.WriteLine($"  Page {page.PageNumber}: {page.Width} x {page.Height} {unit}");
                }
            }
            #endregion

            #region Assertion:ContentUnderstandingAnalyzeUrlAsync
            Assert.IsNotNull(uriSource, "URI source should not be null");
            Assert.IsTrue(uriSource.IsAbsoluteUri, "URI should be absolute");
            Assert.IsNotNull(operation, "Analysis operation should not be null");
            Assert.IsTrue(operation.HasCompleted, "Operation should be completed");
            Assert.IsTrue(operation.HasValue, "Operation should have a value");
            Assert.IsNotNull(operation.GetRawResponse(), "Analysis operation should have a raw response");
            Assert.IsTrue(operation.GetRawResponse().Status >= 200 && operation.GetRawResponse().Status < 300,
                $"Response status should be successful, but was {operation.GetRawResponse().Status}");
            Console.WriteLine("Analysis operation properties verified");
            Assert.IsNotNull(result, "Analysis result should not be null");
            Assert.IsNotNull(result.Contents, "Result contents should not be null");
            Console.WriteLine($"Analysis result contains {result.Contents?.Count ??  0} content(s)");
            #endregion

            // A PDF file has only one content element even if it contains multiple pages
            Console.WriteLine(content.Markdown);
            Assert.IsNotNull(result.Contents, "Result should contain contents");
            Assert.IsTrue(result.Contents!.Count > 0, "Result should have at least one content");
            Assert.AreEqual(1, result.Contents.Count, "PDF file should have exactly one content element");
            Assert.IsNotNull(content, "Content should not be null");
            Assert.IsInstanceOf<AnalysisContent>(content, "Content should be of type AnalysisContent");
            if (content is AnalysisContent mediaContent)
            {
                Assert.IsNotNull(mediaContent.Markdown, "Markdown content should not be null");
                Assert.IsTrue(mediaContent.Markdown.Length > 0, "Markdown content should not be empty");
                Assert.IsFalse(string.IsNullOrWhiteSpace(mediaContent.Markdown),
                    "Markdown content should not be just whitespace");
                Console.WriteLine($"Markdown content extracted successfully ({mediaContent.Markdown.Length} characters)");
            }

            Assert.IsNotNull(content, "Content should not be null for document properties validation");
            Assert.IsInstanceOf<DocumentContent>(content, "Content should be of type DocumentContent");
            DocumentContent docContent = (DocumentContent)content;

            // Validate MIME type
            Assert.IsNotNull(docContent.MimeType, "MIME type should not be null");
            Assert.IsFalse(string.IsNullOrWhiteSpace(docContent.MimeType), "MIME type should not be empty");
            Assert.AreEqual("application/pdf", docContent.MimeType, "MIME type should be application/pdf");
            Console.WriteLine($"MIME type verified: {docContent.MimeType}");

            // Validate page numbers
            Assert.IsTrue(docContent.StartPageNumber >= 1, "Start page should be >= 1");
            Assert.IsTrue(docContent.EndPageNumber >= docContent.StartPageNumber,
                "End page should be >= start page");
            int totalPages = docContent.EndPageNumber - docContent.StartPageNumber + 1;
            Assert.IsTrue(totalPages > 0, "Total pages should be positive");
            Console.WriteLine($"Page range verified: {docContent.StartPageNumber} to {docContent.EndPageNumber} ({totalPages} pages)");

            // Validate pages collection
            Assert.IsNotNull(docContent.Pages, "Pages collection should not be null");
            Assert.IsTrue(docContent.Pages.Count > 0, "Pages collection should not be empty");
            Assert.AreEqual(totalPages, docContent.Pages.Count,
                "Pages collection count should match calculated total pages");
            Console.WriteLine($"Pages collection verified: {docContent.Pages.Count} pages");

            // Track page numbers to ensure they're sequential and unique
            var pageNumbers = new System.Collections.Generic.HashSet<int>();

            foreach (var page in docContent.Pages)
            {
                Assert.IsNotNull(page, "Page object should not be null");
                Assert.IsTrue(page.PageNumber >= 1, "Page number should be >= 1");
                Assert.IsTrue(page.PageNumber >= docContent.StartPageNumber &&
                            page.PageNumber <= docContent.EndPageNumber,
                    $"Page number {page.PageNumber} should be within document range [{docContent.StartPageNumber}, {docContent.EndPageNumber}]");
                Assert.IsTrue(page.Width > 0, $"Page {page.PageNumber} width should be > 0, but was {page.Width}");
                Assert.IsTrue(page.Height > 0, $"Page {page.PageNumber} height should be > 0, but was {page.Height}");

                // Ensure page numbers are unique
                Assert.IsTrue(pageNumbers.Add(page.PageNumber),
                    $"Page number {page.PageNumber} appears multiple times");

                Console.WriteLine($"  Page {page.PageNumber}: {page.Width} x {page.Height} {docContent.Unit?.ToString() ?? "units"}");
            }

            // Validate tables collection
            Assert.IsNotNull(docContent.Tables, "Tables collection should not be null");
            Assert.IsTrue(docContent.Tables.Count > 0, "Tables collection should not be empty");
            Console.WriteLine($"Tables collection verified: {docContent.Tables.Count} tables");

            int tableCounter = 1;
            foreach (var table in docContent.Tables)
            {
                Assert.IsNotNull(table, $"Table {tableCounter} should not be null");
                Assert.IsTrue(table.RowCount > 0, $"Table {tableCounter} should have at least 1 row, but had {table.RowCount}");
                Assert.IsTrue(table.ColumnCount > 0, $"Table {tableCounter} should have at least 1 column, but had {table.ColumnCount}");

                // Validate table cells if available
                if (table.Cells != null)
                {
                    Assert.IsTrue(table.Cells.Count > 0, $"Table {tableCounter} cells collection should not be empty when not null");

                    foreach (var cell in table.Cells)
                    {
                        Assert.IsNotNull(cell, "Table cell should not be null");
                        Assert.IsTrue(cell.RowIndex >= 0 && cell.RowIndex < table.RowCount,
                            $"Cell row index {cell.RowIndex} should be within table row count {table.RowCount}");
                        Assert.IsTrue(cell.ColumnIndex >= 0 && cell.ColumnIndex < table.ColumnCount,
                            $"Cell column index {cell.ColumnIndex} should be within table column count {table.ColumnCount}");
                    }
                }

                Console.WriteLine($"  Table {tableCounter}: {table.RowCount} rows x {table.ColumnCount} columns" +
                    (table.Cells != null ? $" ({table.Cells.Count} cells)" : ""));
                tableCounter++;
            }

            Console.WriteLine("All document properties validated successfully");

            #region Snippet:ContentUnderstandingAnalyzeUrlWithContentRangeAsync
            // Use ContentRange to analyze only specific pages of a document:
            //   ContentRange.Page(1)              — single page ("1")
            //   ContentRange.Pages(1, 3)          — page range ("1-3")
            //   ContentRange.PagesFrom(9)         — from page 9 onward ("9-")
            //   ContentRange.Combine(
            //       ContentRange.Pages(1, 3),
            //       ContentRange.Page(5),
            //       ContentRange.PagesFrom(9))    — combined ranges ("1-3,5,9-")
            Operation<AnalysisResult> rangeOperation = await client.AnalyzeAsync(
                WaitUntil.Completed,
                "prebuilt-documentSearch",
                inputs: new[]
                {
                    new AnalysisInput
                    {
                        Uri = uriSource,
                        ContentRange = ContentRange.Page(1)
                    }
                });

            AnalysisResult rangeResult = rangeOperation.Value;
            DocumentContent rangeDocContent = (DocumentContent)rangeResult.Contents!.First();
            Console.WriteLine($"ContentRange analysis returned pages {rangeDocContent.StartPageNumber} - {rangeDocContent.EndPageNumber}");
            #endregion

            #region Assertion:ContentUnderstandingAnalyzeUrlWithContentRangeAsync
            Assert.IsNotNull(rangeOperation);
            Assert.IsTrue(rangeOperation.HasCompleted);
            Assert.IsNotNull(rangeResult);
            Assert.IsNotNull(rangeResult.Contents);

            // Verify the range-limited result returns only page 1
            Assert.AreEqual(1, rangeDocContent.Pages!.Count, "With ContentRange.Page(1), should return only 1 page");
            Assert.AreEqual(1, rangeDocContent.StartPageNumber, "Page(1) should start at page 1");
            Assert.AreEqual(1, rangeDocContent.EndPageNumber, "Page(1) should end at page 1");

            // Compare full (4 pages) vs range-limited (1 page): full should have more content
            Assert.IsTrue(docContent.Pages!.Count > rangeDocContent.Pages.Count,
                $"Full document ({docContent.Pages.Count} pages) should have more pages than range-limited ({rangeDocContent.Pages.Count})");
            Assert.IsTrue(docContent.Markdown!.Length > rangeDocContent.Markdown!.Length,
                $"Full document markdown ({docContent.Markdown.Length} chars) should exceed range-limited ({rangeDocContent.Markdown.Length} chars)");

            Console.WriteLine($"Full document: {docContent.Pages.Count} pages, {docContent.Markdown.Length} chars");
            Console.WriteLine($"Range document: {rangeDocContent.Pages.Count} page(s), {rangeDocContent.Markdown.Length} chars (page {rangeDocContent.StartPageNumber})");
            #endregion
        }

        [RecordedTest]
        public async Task AnalyzeVideoUrlAsync()
        {
            string endpoint = TestEnvironment.Endpoint;
            var options = InstrumentClientOptions(new ContentUnderstandingClientOptions());
            var client = InstrumentClient(new ContentUnderstandingClient(new Uri(endpoint), TestEnvironment.Credential, options));

            #region Snippet:ContentUnderstandingAnalyzeVideoUrlAsync
            Uri uriSource = new Uri("https://raw.githubusercontent.com/Azure-Samples/azure-ai-content-understanding-assets/main/videos/sdk_samples/FlightSimulator.mp4");

            Operation<AnalysisResult> operation = await client.AnalyzeAsync(
                WaitUntil.Completed,
                "prebuilt-videoSearch",
                inputs: new[]
                {
                    new AnalysisInput
                    {
                        Uri = uriSource
                    }
                });

            AnalysisResult result = operation.Value;

            // prebuilt-videoSearch can detect video segments, so we should iterate through all segments
            int segmentIndex = 1;
            foreach (AnalysisContent media in result.Contents!)
            {
                // Cast AnalysisContent to AudioVisualContent to access audio/visual-specific properties
                // AudioVisualContent derives from AnalysisContent and provides additional properties
                // to access full information about audio/video, including timing, transcript phrases, and many others
                AudioVisualContent videoContent = (AudioVisualContent)media;
                Console.WriteLine($"--- Segment {segmentIndex} ---");
                Console.WriteLine("Markdown:");
                Console.WriteLine(videoContent.Markdown);

                string summary = videoContent.Fields["Summary"].Value?.ToString() ?? string.Empty;
                Console.WriteLine($"Summary: {summary}");

                Console.WriteLine($"Start: {videoContent.StartTime.TotalMilliseconds} ms, End: {videoContent.EndTime.TotalMilliseconds} ms");
                Console.WriteLine($"Frame size: {videoContent.Width} x {videoContent.Height}");

                Console.WriteLine("---------------------");
                segmentIndex++;
            }
            #endregion

            #region Assertion:ContentUnderstandingAnalyzeVideoUrlAsync
            Assert.IsNotNull(operation);
            Assert.IsTrue(operation.HasCompleted);
            Assert.IsTrue(operation.HasValue);
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Contents);
            Assert.IsTrue(result.Contents.Count > 0);
            Assert.IsTrue(result.Contents.All(c => c is AudioVisualContent), "Video analysis should return audio/visual content.");
            Assert.IsTrue(result.Contents.All(c => !string.IsNullOrWhiteSpace(c.Fields["Summary"].Value?.ToString())),
                "All video segments should include a Summary field.");
            #endregion

            #region Snippet:ContentUnderstandingAnalyzeVideoUrlWithContentRangeAsync
            // Use ContentRange.TimeRange to analyze a specific time window of the video.
            // TimeRange and TimeRangeFrom accept TimeSpan values (converted to milliseconds on the wire).
            // You can also use ContentRange.TimeRangeFrom(start) to analyze from a given time onward.
            Operation<AnalysisResult> rangeOperation = await client.AnalyzeAsync(
                WaitUntil.Completed,
                "prebuilt-videoSearch",
                inputs: new[]
                {
                    new AnalysisInput
                    {
                        Uri = uriSource,
                        ContentRange = ContentRange.TimeRange(
                            TimeSpan.Zero,
                            TimeSpan.FromSeconds(5))
                    }
                });

            AnalysisResult rangeResult = rangeOperation.Value;
            foreach (AnalysisContent rangeMedia in rangeResult.Contents!)
            {
                AudioVisualContent rangeVideoContent = (AudioVisualContent)rangeMedia;
                Console.WriteLine($"ContentRange segment: {rangeVideoContent.StartTime.TotalMilliseconds} ms - {rangeVideoContent.EndTime.TotalMilliseconds} ms");
            }
            #endregion

            #region Assertion:ContentUnderstandingAnalyzeVideoUrlWithContentRangeAsync
            Assert.IsNotNull(rangeOperation);
            Assert.IsTrue(rangeOperation.HasCompleted);
            Assert.IsNotNull(rangeResult);
            Assert.IsNotNull(rangeResult.Contents);
            Assert.IsTrue(rangeResult.Contents.Count > 0, "ContentRange video analysis should return segments");
            Assert.IsTrue(rangeResult.Contents.All(c => c is AudioVisualContent), "ContentRange video analysis should return audio/visual content.");

            // Compare full vs range-limited: full analysis should cover more content
            var fullSegments = result.Contents.Cast<AudioVisualContent>().ToList();
            var rangeSegments = rangeResult.Contents.Cast<AudioVisualContent>().ToList();

            // Full video should have more or equal segments than range-limited
            Assert.IsTrue(fullSegments.Count >= rangeSegments.Count,
                $"Full video ({fullSegments.Count} segments) should have >= segments than range-limited ({rangeSegments.Count})");

            // Compare full vs range durations and markdown lengths.
            // Note: The service may return content beyond the requested range for video,
            // so we use >= to avoid flaky tests while verifying the API accepts ContentRange.
            double fullTotalDurationMs = fullSegments.Sum(s => (s.EndTime - s.StartTime).TotalMilliseconds);
            double rangeTotalDurationMs = rangeSegments.Sum(s => (s.EndTime - s.StartTime).TotalMilliseconds);
            Assert.IsTrue(fullTotalDurationMs >= rangeTotalDurationMs,
                $"Full video duration ({fullTotalDurationMs} ms) should be >= range-limited ({rangeTotalDurationMs} ms)");

            int fullMarkdownLength = fullSegments.Sum(s => s.Markdown?.Length ?? 0);
            int rangeMarkdownLength = rangeSegments.Sum(s => s.Markdown?.Length ?? 0);
            Assert.IsTrue(fullMarkdownLength >= rangeMarkdownLength,
                $"Full video markdown ({fullMarkdownLength} chars) should be >= range-limited ({rangeMarkdownLength} chars)");

            // Verify range segments are well-formed
            foreach (var seg in rangeSegments)
            {
                Assert.IsTrue(seg.EndTime > seg.StartTime,
                    $"Range segment should have EndTime > StartTime");
            }

            Console.WriteLine($"Full video: {fullSegments.Count} segment(s), {fullTotalDurationMs} ms, {fullMarkdownLength} chars");
            Console.WriteLine($"Range video: {rangeSegments.Count} segment(s), {rangeTotalDurationMs} ms, {rangeMarkdownLength} chars");
            #endregion
        }

        [RecordedTest]
        public async Task AnalyzeAudioUrlAsync()
        {
            string endpoint = TestEnvironment.Endpoint;
            var options = InstrumentClientOptions(new ContentUnderstandingClientOptions());
            var client = InstrumentClient(new ContentUnderstandingClient(new Uri(endpoint), TestEnvironment.Credential, options));

            #region Snippet:ContentUnderstandingAnalyzeAudioUrlAsync
            Uri uriSource = new Uri("https://raw.githubusercontent.com/Azure-Samples/azure-ai-content-understanding-assets/main/audio/callCenterRecording.mp3");

            Operation<AnalysisResult> operation = await client.AnalyzeAsync(
                WaitUntil.Completed,
                "prebuilt-audioSearch",
                inputs: new[]
                {
                    new AnalysisInput
                    {
                        Uri = uriSource
                    }
                });

            AnalysisResult result = operation.Value;

            // Cast AnalysisContent to AudioVisualContent to access audio/visual-specific properties
            // AudioVisualContent derives from AnalysisContent and provides additional properties
            // to access full information about audio/video, including timing, transcript phrases, and many others
            AudioVisualContent audioContent = (AudioVisualContent)result.Contents!.First();
            Console.WriteLine("Markdown:");
            Console.WriteLine(audioContent.Markdown);

            string summary = audioContent.Fields["Summary"].Value?.ToString() ?? string.Empty;
            Console.WriteLine($"Summary: {summary}");

            // Example: Access an additional field in AudioVisualContent (transcript phrases)
            if (audioContent.TranscriptPhrases != null && audioContent.TranscriptPhrases.Count > 0)
            {
                Console.WriteLine("Transcript (first two phrases):");
                foreach (TranscriptPhrase phrase in audioContent.TranscriptPhrases.Take(2))
                {
                    Console.WriteLine($"  [{phrase.Speaker}] {phrase.StartTime.TotalMilliseconds} ms: {phrase.Text}");
                }
            }
            #endregion

            #region Assertion:ContentUnderstandingAnalyzeAudioUrlAsync
            Assert.IsNotNull(operation);
            Assert.IsTrue(operation.HasCompleted);
            Assert.IsTrue(operation.HasValue);
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Contents);
            Assert.IsTrue(result.Contents.Count > 0);
            Assert.IsInstanceOf<AudioVisualContent>(audioContent);
            Assert.IsTrue(result.Contents.All(c => c is AudioVisualContent), "Audio analysis should return audio/visual content.");
            Assert.IsTrue(result.Contents.All(c => !string.IsNullOrWhiteSpace(c.Fields["Summary"].Value?.ToString())),
                "Audio analysis should include a Summary field.");
            #endregion

            #region Snippet:ContentUnderstandingAnalyzeAudioUrlWithContentRangeAsync
            // Use ContentRange.TimeRangeFrom to analyze from a specific time onward.
            // This analyzes all audio from 5 seconds into the recording to the end.
            // You can also use ContentRange.TimeRange(start, end) to specify an exact time window.
            Operation<AnalysisResult> rangeOperation = await client.AnalyzeAsync(
                WaitUntil.Completed,
                "prebuilt-audioSearch",
                inputs: new[]
                {
                    new AnalysisInput
                    {
                        Uri = uriSource,
                        ContentRange = ContentRange.TimeRangeFrom(
                            TimeSpan.FromSeconds(5))
                    }
                });

            AnalysisResult rangeResult = rangeOperation.Value;
            AudioVisualContent rangeAudioContent = (AudioVisualContent)rangeResult.Contents!.First();
            Console.WriteLine($"ContentRange audio analysis: {rangeAudioContent.StartTime.TotalMilliseconds} ms onward");
            Console.WriteLine($"Summary: {rangeAudioContent.Fields["Summary"].Value}");
            #endregion

            #region Assertion:ContentUnderstandingAnalyzeAudioUrlWithContentRangeAsync
            Assert.IsNotNull(rangeOperation);
            Assert.IsTrue(rangeOperation.HasCompleted);
            Assert.IsNotNull(rangeResult);
            Assert.IsNotNull(rangeResult.Contents);
            Assert.IsTrue(rangeResult.Contents.Count > 0);
            Assert.IsInstanceOf<AudioVisualContent>(rangeAudioContent);

            // Compare full vs range-limited content.
            // Note: The service may return content beyond the requested range for audio,
            // so we use >= to avoid flaky tests while verifying the API accepts ContentRange.
            Assert.IsTrue(audioContent.Markdown!.Length >= rangeAudioContent.Markdown!.Length,
                $"Full audio markdown ({audioContent.Markdown.Length} chars) should be >= range-limited ({rangeAudioContent.Markdown.Length} chars)");

            int fullPhraseCount = audioContent.TranscriptPhrases?.Count ?? 0;
            int rangePhraseCount = rangeAudioContent.TranscriptPhrases?.Count ?? 0;
            Assert.IsTrue(fullPhraseCount >= rangePhraseCount,
                $"Full audio ({fullPhraseCount} phrases) should have >= phrases than range-limited ({rangePhraseCount} phrases)");

            double fullDurationMs = (audioContent.EndTime - audioContent.StartTime).TotalMilliseconds;
            double rangeDurationMs = (rangeAudioContent.EndTime - rangeAudioContent.StartTime).TotalMilliseconds;
            Assert.IsTrue(fullDurationMs >= rangeDurationMs,
                $"Full audio duration ({fullDurationMs} ms) should be >= range-limited ({rangeDurationMs} ms)");

            Console.WriteLine($"Full audio: {audioContent.Markdown.Length} chars, {fullPhraseCount} phrases, {fullDurationMs} ms");
            Console.WriteLine($"Range audio: {rangeAudioContent.Markdown.Length} chars, {rangePhraseCount} phrases, {rangeDurationMs} ms, starts at {rangeAudioContent.StartTime}");
            #endregion
        }

